import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, fw, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv != av:
        changes.append((proj, fw, pkg, bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((proj, fw, pkg, av))

if changes:
    print('CHANGES:')
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')
else:
    print('NO CHANGES')

print(f'\nUnchanged: {len(unchanged)} entries')
print(f'Changed: {len(changes)} entries')
"

